import{c as t,Q as r,j as a,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse(`{"title":"Ben's Bites — 2026-05-05","description":"","frontmatter":{"title":"Ben's Bites — 2026-05-05","date":"2026-05-05T00:00:00.000Z","source":"Ben's Bites","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-05-bens-bites.md","filePath":"research/ai-news/2026-05/2026-05-05-bens-bites.md","lastUpdated":1779796674000}`),s={name:"research/ai-news/2026-05/2026-05-05-bens-bites.md"};function o(i,e,l,p,h,c){return r(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="🍔-ben-s-bites-—-2026-05-05" tabindex="-1">🍔 Ben&#39;s Bites — 2026-05-05 <a class="header-anchor" href="#🍔-ben-s-bites-—-2026-05-05" aria-label="Permalink to &quot;🍔 Ben&#39;s Bites — 2026-05-05&quot;">​</a></h1><blockquote><p>Ben Tossell 的 AI 日報，工具圈消息源 來源：<a href="https://www.bensbites.com/feed" target="_blank" rel="noreferrer">Ben&#39;s Bites</a></p></blockquote><hr><h2 id="codex-is-gaining-steam" tabindex="-1"><a href="https://www.bensbites.com/p/codex-is-gaining-steam" target="_blank" rel="noreferrer">Codex is gaining steam</a> <a class="header-anchor" href="#codex-is-gaining-steam" aria-label="Permalink to &quot;[Codex is gaining steam](https://www.bensbites.com/p/codex-is-gaining-steam)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-05-05</em></p><p>Hey folks,</p><p>I spent most of the bank holiday weekend offline for a change whilst at a wedding in the English countryside. I would’ve been more online if Codex had a mobile app but still waiting on that… this morning I did just <a href="https://github.com/gragland/codex-imessage-handoff" target="_blank" rel="noreferrer">install this skill</a> that lets you iMessage Codex which is pretty great - essentially keeps a thread open in the app that you can message. Just paste the link in Codex and it’ll guide you through everything.</p><p>Ben’s Bites is brought to you by <a href="https://www.gravitee.io/?utm_source=bensbites&amp;utm_medium=newsletter&amp;utm_campaign=beachhead&amp;utm_content=1" target="_blank" rel="noreferrer">Gravitee</a></p><p>As AI Agents connect to more APIs, security risk gets harder to manage. <a href="https://www.gravitee.io/?utm_source=bensbites&amp;utm_medium=newsletter&amp;utm_campaign=beachhead&amp;utm_content=1" target="_blank" rel="noreferrer">Gravitee</a> helps teams govern APIs, events, and AI Agents while reducing silos and cost. See what enterprise teams are prioritizing in the <a href="https://www.gravitee.io/state-of-ai-agent-security/?utm_source=bensbites&amp;utm_medium=newsletter&amp;utm_campaign=beachhead&amp;utm_content=1" target="_blank" rel="noreferrer">State of AI Agent Security report.</a></p><p>Headlines</p><p>OpenAI wants non-technical users to use Codex. They are making it easy for you to <a href="https://chatgpt.com/codex/switch-to-codex/" target="_blank" rel="noreferrer">switch to Codex</a>. You can now import settings, plugins, agents, project configuration and more into Codex (from tools like Claude Cowork). They are directly improving features <a href="https://chatgpt.com/codex/for-work/" target="_blank" rel="noreferrer">related to everyday work</a>, like creating slides/sheets, plus friendlier UI changes.</p><p><a href="https://docs.x.ai/developers/models/grok-4.3" target="_blank" rel="noreferrer">Grok 4.3 is out in the API</a>. 1M context, text + image input, reasoning and a December 2025 knowledge cutoff. It’s priced $1.25/$2.50 per million input/output tokens, i.e. much cheaper than Sonnet 4.6 for a relatively similar performance.</p><p>Entire, the company by GitHub’s ex-CEO, released two new things: <a href="https://github.com/entireio/git-sync" target="_blank" rel="noreferrer">git-sync</a> - a utility to mirror git repos from a source to a target without needing to clone it locally and <a href="https://x.com/EntireHQ/status/2051331019425624209" target="_blank" rel="noreferrer">Dispatches</a> - a feature on their web platform to generate release notes from recent ships, commits, and agent sessions by repo/date range.</p><p>Charity Majors and Christine Yen headline <a href="https://fandf.co/3QVdYGu" target="_blank" rel="noreferrer">Honeycomb&#39;s Innovation Week</a> (May 12–14), a 3-day virtual event addressing observability for the agent era. Learn how the most forward-thinking engineering teams are rising to meet this challenge. <a href="https://fandf.co/3QVdYGu" target="_blank" rel="noreferrer">Register now</a>.*</p><p>My feed</p><p>Lightfield - AI-native CRM that learns how you sell. Describe any workflow in English, your CRM runs it on command. <a href="https://lightfield.app/blog/introducing-skills?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=bens_bites&amp;utm_content=tools_5-5-2026" target="_blank" rel="noreferrer">3 mo free w/ </a><a href="https://lightfield.app/blog/introducing-skills?utm_source=newsletter&amp;utm_medium=paid&amp;utm_campaign=bens_bites&amp;utm_content=tools_5-5-2026" target="_blank" rel="noreferrer">BENSBITEST13</a>*</p><p><a href="https://www.sauna.ai/" target="_blank" rel="noreferrer">Sauna</a> - learns how you work, remembers everything that matters, and actions on it (portfolio company!)</p><p><a href="https://zapier.com/shared-brain" target="_blank" rel="noreferrer">Shared Brain by Zapier</a> - Collective knowledge vault for your team and a personal assistant to complete tasks. Now in early access.</p><p><a href="https://manus.im/blog/manus-cloud-computer" target="_blank" rel="noreferrer">Manus Cloud Computer</a> - always-on cloud machine for Manus so bots, scripts, databases and scheduled jobs keep running when your laptop is off. Files and installed tools persist across sessions.</p><p><a href="https://proxyuser.com/" target="_blank" rel="noreferrer">Proxyuser</a> - test all the core flows of your app via a synthetic user with a real browser, including signups.</p><p><a href="https://webuibench.dev/" target="_blank" rel="noreferrer">Web UI Bench</a> - Same UI components built by 20 models, shown side-by-side. GPT-5.5 uses too much bland text in the UI when an icon or control is self-explanatory (compared to Opus 4.7).</p><p><a href="https://flueframework.com/" target="_blank" rel="noreferrer">Flue</a> - TypeScript framework for building Claude Code-style agents.</p><p><a href="https://vercel.com/blog/introducing-deepsec-find-and-fix-vulnerabilities-in-your-code-base" target="_blank" rel="noreferrer">deepsec</a> - open-source security harness from Vercel for finding vulnerabilities in your codebase with coding agents.</p><p><a href="https://x.com/aidenybai/status/2051331240230613439" target="_blank" rel="noreferrer">localterm</a> - run a terminal in your browser with npx localterm@latest start.</p><p><a href="https://open-slide.dev/" target="_blank" rel="noreferrer">open-slide</a> - slide framework built for agents. Visual edits, comments, assets and agent-readable slide structure.</p><p><a href="https://styles.refero.design/" target="_blank" rel="noreferrer">Refero Styles</a> - 2,000+ DESIGN.md files from real products that your agent can use for style references.</p><p>How OpenAI delivers <a href="https://openai.com/index/delivering-low-latency-voice-ai-at-scale/" target="_blank" rel="noreferrer">low-latency voice AI</a> at scale.</p><p><a href="https://github.com/openclaw/crabbox" target="_blank" rel="noreferrer">crabbox</a> - run your dirty worktrees in a remote sandbox easily. (<a href="https://x.com/steipete/status/2050490163810230579" target="_blank" rel="noreferrer">tweet</a>)</p><p>OpenAI has a new opt-in feature for <a href="https://openai.com/index/advanced-account-security/" target="_blank" rel="noreferrer">Advanced Account Security</a> in ChatGPT/Codex.</p><p><a href="https://x.com/MS_BASE44/status/2049877053248352388" target="_blank" rel="noreferrer">Base44’s Frustration Meter</a> - usage-based model benchmark. Base44 says Opus 4.7 caused 43% more frustration than Opus 4.6.</p><p><a href="https://cofounder.co/resources/introducing-cofounder-2" target="_blank" rel="noreferrer">Cofounder 2</a> - another “run a company with agents” product that’s a combo of vibe coding, finding leads and sending sales emails.</p><p><a href="https://x.com/james406/status/2049886127507878363?s=20" target="_blank" rel="noreferrer">How Posthog plans to change</a> in the AI era.</p><p>Afters</p><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben’s Bites</p><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p><ul><li>sponsors who make this newsletter possible 😃</li></ul><p>Wanna partner with us for the next quarter?</p><p>Email us at <a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></p><hr>',40)])])}const d=t(s,[["render",o]]);export{u as __pageData,d as default};
